root.js-content:
stp.writeLog("Begin: Assign function R2StatusReport");
var MainRef = stp.getValue("/Document/StsRpt/RltdMsgRef","Id");
var bu=stp.getTSUUnitCode();
stp.writeLog("MainRef="+MainRef[0]);

var fld_list       = stp.addFieldList(null,"C_MAIN_REF"); 
var sql_condition = stp.addSQLCondition(null,"TSU_MESSAGE_ID",MainRef[0]); 
sql_condition   = stp.addSQLCondition(sql_condition,"C_UNIT_CODE",bu);   
var result = stp.executeQuery("TSUM_EM_STSRPTREQ",fld_list,sql_condition); 
var C_MAIN_REF = stp.getDBFieldValue(result,"C_MAIN_REF");
stp.writeLog("C_MAIN_REF:"+C_MAIN_REF);

stp.updateFieldValue("/root/domData","C_MAIN_REF",C_MAIN_REF);
stp.updateFieldValue("/root/domData","C_TRX_REF",C_MAIN_REF);
//huyechao modify on 20131220--S
var TxId = stp.getValue("/Document/StsRpt/RptdItms","TxId");
var Llength = TxId.length;
for(var i=0; i<Llength;i++){
	var BIC = stp.getValue("/Document/StsRpt/RptdItms["+stp.toDouble(i+1)+"]/RptdNtty","BIC");
	var BIC1 = BIC[0];
	var BIC2 = BIC[1];
	if(BIC1==undefined)
	{
		BIC1="null";
	}
	if(BIC2==undefined)
	{
		BIC2="null";
	}
	stp.updateFieldValue("/root/domData/R2StatusReportItems2["+stp.toDouble(i+1)+"]","TSU_PARTY_BIC",BIC1);
	stp.updateFieldValue("/root/domData/R2StatusReportItems2["+stp.toDouble(i+1)+"]","TSU_PARTY_BIC2",BIC2);
}
//huyechao modify on 20131220--E
stp.setAutoProcess(true);
stp.setFunc("R2StatusReport");
stp.writeLog("End: R2StatusReport");
